906	/// Convert a proto [`ans_proto::ans::EyeReport`] to core [`ans_core::signal::EyeReport`].
907	/// Returns `None` if the `eye_name` is unrecognized or the content is missing.
908	fn proto_to_core_eye_report(
909	    proto: &ans_proto::ans::EyeReport,
910	) -> Option<ans_core::signal::EyeReport> {
911	    use ans_proto::ans::eye_report::Content;
912	
913	    let eye_name = match proto.eye_name.as_str() {
914	        "dom_reader" => EyeName::DomReader,
915	        "vision" => EyeName::Vision,
916	        "page_diff" => EyeName::PageDiff,
917	        "goal_verifier" => EyeName::GoalVerifier,
918	        "error_detector" => EyeName::ErrorDetector,
919	        _ => return None,
920	    };
921	
922	    let content = match &proto.content {
923	        Some(Content::Dom(dom)) => EyeReportContent::DomReport {
924	            elements: vec![],
925	            interactive: vec![],
926	            mode: dom
927	                .dom
928	                .as_ref()
929	                .map_or(DistillMode::AllFields, |d| match d.mode.as_str() {
930	                    "text_only" => DistillMode::TextOnly,
931	                    "input_fields" => DistillMode::InputFields,
932	                    _ => DistillMode::AllFields,
933	                }),
934	        },
935	        Some(Content::Vision(v)) => EyeReportContent::VisionReport {
936	            visible_elements: v.visible_elements.clone(),
937	            overlays: v.overlays.clone(),
938	            blocked_regions: v.blocked_regions.clone(),
939	            page_type: v.page_type.clone(),
940	            anomalies: v.anomalies.clone(),
941	            raw_response: v.raw_response.clone(),
942	        },
943	        Some(Content::Diff(d)) => {
944	            let diff_report = d.diff.as_ref();
945	            EyeReportContent::DiffReport {
946	                added: diff_report.map_or(vec![], |r| {
947	                    r.added.iter().map(|e| e.selector.clone()).collect()
948	                }),
949	                removed: diff_report.map_or(vec![], |r| {
950	                    r.removed.iter().map(|e| e.selector.clone()).collect()
951	                }),
952	                modified: diff_report.map_or(vec![], |r| {
953	                    r.modified.iter().map(|m| m.selector.clone()).collect()
954	                }),
955	                visual_diff_pct: diff_report.map_or(0.0, |r| r.visual_diff_percentage),
956	                summary: diff_report.map_or(String::new(), |r| r.summary.clone()),
957	            }
958	        }
959	        Some(Content::Verification(v)) => EyeReportContent::Verification {
960	            sub_goal_advanced: v.criteria_status == "met",
961	            confidence: v.confidence,
962	            reasoning: v.reasoning.clone(),
963	            criteria_status: v.criteria_status.clone(),
964	        },
965	        Some(Content::Error(e)) => EyeReportContent::ErrorReport {
966	            failure_type: e.failure_type.clone(),
967	            description: e.description.clone(),
968	            recovery_actions: e.recovery_actions.clone(),
969	            should_retry: e.should_retry,
970	            max_retries: e.max_retries as u32,
971	        },
972	        None => return None,
973	    };
974	
975	    Some(ans_core::signal::EyeReport {
976	        eye_name,
977	        timestamp: chrono::Utc::now(),
978	        confidence: proto.confidence,
979	        goal_relevance: proto.goal_relevance,
980	        content,
981	    })
982	}
