984	/// Format the oneof eye report content into a readable string.
985	fn format_eye_content(content: Option<&ans_proto::ans::eye_report::Content>) -> String {
986	    use ans_proto::ans::eye_report::Content;
987	    match content {
988	        Some(Content::Dom(dom)) => {
989	            format!(
990	                "DOM: {} elements, {} interactive",
991	                dom.dom.as_ref().map_or(0, |d| d.elements.len() as i32),
992	                dom.focused_elements.len()
993	            )
994	        }
995	        Some(Content::Vision(v)) => {
996	            format!(
997	                "Vision: {} visible, {} overlays, type={}",
998	                v.visible_elements.len(),
999	                v.overlays.len(),
1000	                v.page_type
1001	            )
1002	        }
1003	        Some(Content::Diff(d)) => {
1004	            format!(
1005	                "Diff: {}% visual change",
1006	                d.diff.as_ref().map_or(0.0, |r| r.visual_diff_percentage)
1007	            )
1008	        }
1009	        Some(Content::Verification(v)) => {
1010	            format!(
1011	                "Verify: {} (confidence={:.0}%)",
1012	                v.criteria_status,
1013	                v.confidence * 100.0
1014	            )
1015	        }
1016	        Some(Content::Error(e)) => {
1017	            format!("Error: {} — {}", e.failure_type, e.description)
1018	        }
1019	        None => "no content".into(),
1020	    }
1021	}
