1	//! Thread-safe goal state store with broadcast notifications.
2	//!
3	//! Wraps `Arc<RwLock<HashMap<Uuid, GoalState>>>` with `tokio::broadcast`
4	//! on every state mutation. All sessions working on the same goal share
5	//! this store. Cheap to clone (Arc pointer copy only).
6	
7	use std::collections::HashMap;
8	use std::sync::{Arc, RwLock};
9	
10	use ans_core::goal::{GoalState, GoalStatus, SubGoalStatus};
11	use tokio::sync::broadcast;
12	use tracing;
13	use uuid::Uuid;
14	
15	/// Notification sent to subscribers when a goal's state changes.
16	#[derive(Debug, Clone)]
17	pub struct GoalStateNotification {
18	    pub goal_id: Uuid,
19	    pub progress: f32,
20	    pub status: GoalStatus,
21	    pub message: String,
22	}
23	
24	/// Shared goal state store with pub/sub.
25	///
26	/// Cloning shares the underlying state — use this to hand out
27	/// references to the gRPC server, workers, and subscribers.
28	pub struct GoalStateStore {
29	    inner: Arc<RwLock<HashMap<Uuid, GoalState>>>,
30	    tx: broadcast::Sender<GoalStateNotification>,
31	}
32	
33	impl GoalStateStore {
34	    /// Create an empty goal store with room for `capacity` notification
35	    /// listeners before slow consumers are dropped.
36	    #[must_use] 
37	    pub fn new(capacity: usize) -> Self {
38	        let (tx, _) = broadcast::channel(capacity);
39	        Self {
40	            inner: Arc::new(RwLock::new(HashMap::new())),
41	            tx,
42	        }
43	    }
44	
45	    /// Insert a new goal state. Returns error if `goal_id` already exists.
46	    pub fn insert(&self, state: GoalState) -> Result<(), GoalStoreError> {
47	        let goal_id = state.goal_id;
48	        let progress = state.progress;
49	        let status = state.status;
50	
51	        let mut map = self
52	            .inner
53	            .write()
54	            .map_err(|_| GoalStoreError::LockPoisoned)?;
55	        if map.contains_key(&goal_id) {
56	            return Err(GoalStoreError::DuplicateGoal(goal_id));
57	        }
58	        map.insert(goal_id, state);
59	
60	        let _ = self.tx.send(GoalStateNotification {
61	            goal_id,
62	            progress,
63	            status,
64	            message: "Goal created".into(),
65	        });
66	
67	        tracing::info!(%goal_id, "Goal inserted");
68	        Ok(())
69	    }
70	
71	    /// Retrieve a goal state by ID.
72	    #[must_use] 
73	    pub fn get(&self, goal_id: &Uuid) -> Option<GoalState> {
74	        self.inner
75	            .read()
76	            .ok()
77	            .and_then(|map| map.get(goal_id).cloned())
78	    }
79	
80	    /// Update an existing goal state. Fails if goal doesn't exist.
81	    pub fn update(&self, goal_id: Uuid, state: GoalState) -> Result<(), GoalStoreError> {
82	        let progress = state.progress;
83	        let status = state.status;
84	
85	        let mut map = self
86	            .inner
87	            .write()
88	            .map_err(|_| GoalStoreError::LockPoisoned)?;
89	        if !map.contains_key(&goal_id) {
90	            return Err(GoalStoreError::NotFound(goal_id));
91	        }
92	        map.insert(goal_id, state);
93	
94	        let _ = self.tx.send(GoalStateNotification {
95	            goal_id,
96	            progress,
97	            status,
98	            message: "Goal updated".into(),
99	        });
100	
101	        tracing::debug!(%goal_id, %progress, "Goal state updated");
102	        Ok(())
103	    }
104	
105	    /// Update progress and status for an existing goal. Lightweight; doesn't
106	    /// require constructing a full `GoalState`.
107	    pub fn update_progress(
108	        &self,
109	        goal_id: Uuid,
110	        progress: f32,
111	        status: GoalStatus,
112	    ) -> Result<GoalState, GoalStoreError> {
113	        let mut map = self
114	            .inner
115	            .write()
116	            .map_err(|_| GoalStoreError::LockPoisoned)?;
117	        let state = map
118	            .get_mut(&goal_id)
119	            .ok_or(GoalStoreError::NotFound(goal_id))?;
120	
121	        state.progress = progress.clamp(0.0, 1.0);
122	        state.status = status;
123	        state.updated_at = chrono::Utc::now();
124	
125	        if progress >= 1.0 {
126	            state.status = GoalStatus::Completed;
127	        }
128	
129	        let snapshot = state.clone();
130	
131	        let _ = self.tx.send(GoalStateNotification {
132	            goal_id,
133	            progress: state.progress,
134	            status: state.status,
135	            message: format!("Progress: {:.0}%", state.progress * 100.0),
136	        });
137	
138	        tracing::info!(%goal_id, progress = %state.progress, "Goal progress updated");
139	        Ok(snapshot)
140	    }
141	
142	    /// Replace all sub-goals (e.g., from Python LLM decomposer).
143	    pub fn update_sub_goals(
144	        &self,
145	        goal_id: Uuid,
146	        sub_goals: Vec<ans_core::goal::SubGoal>,
147	    ) -> Result<GoalState, GoalStoreError> {
148	        let mut map = self.inner.write().map_err(|_| GoalStoreError::LockPoisoned)?;
149	        let state = map.get_mut(&goal_id).ok_or(GoalStoreError::NotFound(goal_id))?;
150	        let total = sub_goals.len() as f32;
151	        let done = sub_goals.iter().filter(|s| s.status == SubGoalStatus::Done).count() as f32;
152	        let progress = if total > 0.0 { done / total } else { 0.0 };
153	        state.sub_goals = sub_goals;
154	        state.progress = progress;
155	        state.updated_at = chrono::Utc::now();
156	        let snapshot = state.clone();
157	        let _ = self.tx.send(GoalStateNotification {
158	            goal_id, progress: state.progress, status: state.status,
159	            message: format!("Sub-goals updated: {} total", total),
160	        });
161	        tracing::info!(%goal_id, sub_goal_count = total, "Goal sub-goals updated from decomposer");
162	        Ok(snapshot)
163	    }
164	
165	    /// Remove a goal from the store.
166	    pub fn remove(&self, goal_id: &Uuid) -> Option<GoalState> {
167	        let mut map = self.inner.write().ok()?;
168	        let removed = map.remove(goal_id);
169	
170	        if removed.is_some() {
171	            let _ = self.tx.send(GoalStateNotification {
172	                goal_id: *goal_id,
173	                progress: 1.0,
174	                status: GoalStatus::Completed,
175	                message: "Goal removed".into(),
176	            });
177	            tracing::info!(%goal_id, "Goal removed");
178	        }
179	        removed
180	    }
181	
182	    /// List all active goal IDs.
183	    #[must_use] 
184	    pub fn list_ids(&self) -> Vec<Uuid> {
185	        self.inner
186	            .read()
187	            .map(|map| map.keys().copied().collect())
188	            .unwrap_or_default()
189	    }
190	
191	    /// Number of active goals.
192	    #[must_use] 
193	    pub fn len(&self) -> usize {
194	        self.inner.read().map_or(0, |m| m.len())
195	    }
196	
197	    /// Returns true if the store is empty.
198	    #[must_use] 
199	    pub fn is_empty(&self) -> bool {
200	        self.len() == 0
201	    }
202	
203	    /// Subscribe to goal state change notifications.
204	    #[must_use] 
205	    pub fn subscribe(&self) -> broadcast::Receiver<GoalStateNotification> {
206	        self.tx.subscribe()
207	    }
208	}
209	
210	impl Default for GoalStateStore {
211	    fn default() -> Self {
212	        Self::new(256)
213	    }
214	}
215	
216	impl Clone for GoalStateStore {
217	    fn clone(&self) -> Self {
218	        Self {
219	            inner: Arc::clone(&self.inner),
220	            tx: self.tx.clone(),
221	        }
222	    }
223	}
224	
225	/// Errors that can occur during store operations.
226	#[derive(Debug, thiserror::Error)]
227	pub enum GoalStoreError {
228	    #[error("goal {0} already exists")]
229	    DuplicateGoal(Uuid),
230	
231	    #[error("goal {0} not found")]
232	    NotFound(Uuid),
233	
234	    #[error("lock poisoned — store is in an unrecoverable state")]
235	    LockPoisoned,
236	}
