18	    pub async fn connect(grpc_port: u16) -> Result<Self, tonic::transport::Error> {
19	        let addr: &'static str = Box::leak(format!("http://127.0.0.1:{grpc_port}").into_boxed_str());
20	        let channel = Channel::from_static(addr)
21	            .connect()
22	            .await?;
23	        Ok(Self {
24	            inner: AgentNervousSystemClient::new(channel),
25	        })
26	    }
