189	    async fn handle_tools_call(&self, id: Option<Value>, body: &Value) -> Value {
190	        let params = body.get("params");
191	        let tool_name = match params.and_then(|p| p.get("name")).and_then(|n| n.as_str()) {
192	            Some(name) => name,
193	            None => return json_rpc_error(id, -32602, "Missing params.name"),
194	        };
195	
196	        let args = params
197	            .and_then(|p| p.get("arguments"))
198	            .cloned()
199	            .unwrap_or_else(|| json!({}));
200	
201	        let result = match tool_name {
202	            "create_session" => self.tool_create_session(&args).await,
203	            "navigate" => self.tool_navigate(&args).await,
204	            "click" => self.tool_click(&args).await,
205	            "type_text" => self.tool_type_text(&args).await,
206	            "scroll" => self.tool_scroll(&args).await,
207	            "screenshot" => self.tool_screenshot(&args).await,
208	            "get_dom" => self.tool_get_dom(&args).await,
209	            "execute_action" => self.tool_execute_action(&args).await,
210	            "check_goal" => self.tool_check_goal(&args).await,
211	            "create_goal" => self.tool_create_goal(&args).await,
212	            other => return json_rpc_error(id, -32602, &format!("Unknown tool: {other}")),
213	        };
214	
215	        match result {
216	            Ok(content) => json_rpc_result(
217	                id,
218	                json!({ "content": [{ "type": "text", "text": content }] }),
219	            ),
220	            Err(e) => json_rpc_error(id, -32000, &e),
221	        }
222	    }
223	
224	    // ── Tool implementations ──────────────────────────────────────────
225	
226	    fn str_arg<'a>(args: &'a Value, key: &str) -> Option<&'a str> {
227	        args.get(key).and_then(|v| v.as_str())
228	    }
229	
230	    async fn tool_create_session(&self, args: &Value) -> Result<String, String> {
231	        let goal_id = Self::str_arg(args, "goal_id").unwrap_or("");
232	        let start_url = Self::str_arg(args, "start_url").unwrap_or("about:blank");
233	
234	        let mut client = self.client.clone_client();
235	        let req = tonic::Request::new(ans_proto::ans::CreateSessionRequest {
236	            goal_id: goal_id.into(),
237	            start_url: start_url.into(),
238	            headers: std::collections::HashMap::new(),
239	        });
240	
241	        let resp = client
242	            .create_session(req)
243	            .await
244	            .map_err(|e| format!("gRPC error: {e}"))?
245	            .into_inner();
246	
247	        Ok(serde_json::to_string_pretty(&json!({
248	            "session_id": resp.session_id,
249	            "goal_id": resp.goal_id,
250	            "status": resp.status,
251	            "created_at": resp.created_at,
252	        }))
253	        .unwrap_or_else(|e| format!("serialization error: {e}")))
254	    }
255	
256	    async fn tool_navigate(&self, args: &Value) -> Result<String, String> {
257	        let session_id = Self::str_arg(args, "session_id").ok_or("session_id required")?;
258	        let url = Self::str_arg(args, "url").ok_or("url required")?;
259	
260	        let mut client = self.client.clone_client();
261	        let req = tonic::Request::new(ans_proto::ans::NavigateRequest {
262	            session_id: session_id.into(),
263	            url: url.into(),
264	            timeout_ms: 30000,
265	        });
266	
267	        let resp = client
268	            .navigate(req)
269	            .await
270	            .map_err(|e| format!("gRPC error: {e}"))?
271	            .into_inner();
272	
273	        Ok(serde_json::to_string_pretty(&json!({
274	            "url": resp.url,
275	            "title": resp.title,
276	            "loaded": resp.loaded,
277	            "dom_node_count": resp.dom_node_count,
278	        }))
279	        .unwrap_or_else(|e| format!("serialization error: {e}")))
280	    }
281	
