470	fn json_rpc_result(id: Option<Value>, result: Value) -> Value {
471	    json!({
472	        "jsonrpc": "2.0",
473	        "id": id.unwrap_or(Value::Null),
474	        "result": result
475	    })
476	}
477	
478	fn json_rpc_error(id: Option<Value>, code: i32, message: &str) -> Value {
479	    json!({
480	        "jsonrpc": "2.0",
481	        "id": id.unwrap_or(Value::Null),
482	        "error": {
483	            "code": code,
484	            "message": message
485	        }
486	    })
487	}
