1	//! API key authentication for the Layer 1 gateway.
2	//!
3	//! Loads `api_keys.json` at startup. Each key has scoped permissions:
4	//! read-only, session-create, or full-access. All MCP, REST, and
5	//! WebSocket endpoints validate the `X-API-Key` header through this
6	//! module before any gRPC call is made.
7	
8	use serde::{Deserialize, Serialize};
9	use std::collections::HashMap;
10	use std::path::PathBuf;
11	use std::sync::Arc;
12	
13	/// Permissions scoped to an API key.
14	#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize)]
15	#[serde(rename_all = "lowercase")]
16	pub enum KeyPermission {
17	    ReadOnly,
18	    SessionCreate,
19	    FullAccess,
20	}
21	
22	impl KeyPermission {
23	    /// Returns true if this permission allows creating sessions.
24	    #[must_use] 
25	    pub const fn can_create_session(&self) -> bool {
26	        matches!(
27	            self,
28	            Self::SessionCreate | Self::FullAccess
29	        )
30	    }
31	
32	    /// Returns true if this permission allows mutating state.
33	    #[must_use] 
34	    pub const fn can_write(&self) -> bool {
35	        matches!(
36	            self,
37	            Self::SessionCreate | Self::FullAccess
38	        )
39	    }
40	
41	    /// Returns true if this permission allows reading state.
42	    #[must_use] 
43	    pub const fn can_read(&self) -> bool {
44	        true // all permissions allow reading
45	    }
46	}
47	
48	/// A single API key entry.
49	#[derive(Debug, Clone, Serialize, Deserialize)]
50	pub struct ApiKeyEntry {
51	    pub key: String,
52	    pub name: String,
53	    pub permission: KeyPermission,
54	}
55	
56	/// The API key registry, loaded from disk at startup.
57	#[derive(Debug, Clone, Serialize, Deserialize)]
58	pub struct KeyRegistry {
59	    keys: HashMap<String, ApiKeyEntry>,
60	}

