1	//! Integration tests for the gRPC IPC server.
2	//!
3	//! Tests the gRPC service implementation for non-browser RPCs
4	//! (health, goals, decisions, immune) using an in-process server.
5	
6	#![allow(clippy::unwrap_used)]
7	
8	use std::collections::HashMap;
9	use std::net::{IpAddr, Ipv4Addr, SocketAddr};
10	
11	use ans_ipc::server::IpcServer;
12	use ans_proto::ans::agent_nervous_system_client::AgentNervousSystemClient;
13	use ans_proto::ans::{
14	    Action, ActionCheckRequest, CreateGoalRequest, DistractionRequest, Empty,
15	    GoalStateRequest, InjectionScanRequest, QueryBestActionsRequest, StoreScoreRequest,
16	};
17	use tonic::transport::Server;
