19	/// Start a gRPC test server on a random port, returning the bound address.
20	async fn start_test_server() -> SocketAddr {
21	    let ipc = IpcServer::new();
22	    let svc = ipc.into_tonic_service();
23	
24	    let addr = SocketAddr::new(IpAddr::V4(Ipv4Addr::LOCALHOST), 0);
25	    let listener = tokio::net::TcpListener::bind(addr).await.unwrap();
26	    let bound_addr = listener.local_addr().unwrap();
27	
28	    tokio::spawn(async move {
29	        Server::builder()
30	            .add_service(svc)
31	            .serve_with_incoming(tokio_stream::wrappers::TcpListenerStream::new(listener))
32	            .await
33	            .unwrap();
34	    });
35	
36	    // Give the server a moment to start
37	    tokio::time::sleep(std::time::Duration::from_millis(100)).await;
38	    bound_addr
39	}
