45	        .await
46	        .unwrap();
47	
48	    let response = client.health(tonic::Request::new(Empty {})).await;
49	    assert!(response.is_ok());
50	
51	    let health = response.unwrap().into_inner();
52	    assert!(health.healthy);
53	    assert!(!health.version.is_empty());
